import{_ as o,o as a,c as i,ai as d}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Bridge Protocol","description":"","frontmatter":{"summary":"Bridge protocol (legacy nodes): TCP JSONL, pairing, scoped RPC","read_when":["Building or debugging node clients (iOS/Android/macOS node mode)","Investigating pairing or bridge auth failures","Auditing the node surface exposed by the gateway"],"title":"Bridge Protocol"},"headers":[],"relativePath":"gateway/bridge-protocol.md","filePath":"gateway/bridge-protocol.md","lastUpdated":1771906665000}'),t={name:"gateway/bridge-protocol.md"};function n(r,e,c,s,l,g){return a(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="bridge-protocol-legacy-node-transport" tabindex="-1"><a class="header-anchor" href="#bridge-protocol-legacy-node-transport">#</a> Bridge protocol (legacy node transport)</h1><p>The Bridge protocol is a <strong>legacy</strong> node transport (TCP JSONL). New node clients should use the unified Gateway WebSocket protocol instead.</p><p>If you are building an operator or node client, use the <a href="/docs/gateway/protocol">Gateway protocol</a>.</p><p><strong>Note:</strong> Current OpenSoul builds no longer ship the TCP bridge listener; this document is kept for historical reference. Legacy <code>bridge.*</code> config keys are no longer part of the config schema.</p><h2 id="why-we-have-both" tabindex="-1"><a class="header-anchor" href="#why-we-have-both">#</a> Why we have both</h2><ul><li><strong>Security boundary</strong>: the bridge exposes a small allowlist instead of the full gateway API surface.</li><li><strong>Pairing + node identity</strong>: node admission is owned by the gateway and tied to a per-node token.</li><li><strong>Discovery UX</strong>: nodes can discover gateways via Bonjour on LAN, or connect directly over a tailnet.</li><li><strong>Loopback WS</strong>: the full WS control plane stays local unless tunneled via SSH.</li></ul><h2 id="transport" tabindex="-1"><a class="header-anchor" href="#transport">#</a> Transport</h2><ul><li>TCP, one JSON object per line (JSONL).</li><li>Optional TLS (when <code>bridge.tls.enabled</code> is true).</li><li>Legacy default listener port was <code>18790</code> (current builds do not start a TCP bridge).</li></ul><p>When TLS is enabled, discovery TXT records include <code>bridgeTls=1</code> plus <code>bridgeTlsSha256</code> so nodes can pin the certificate.</p><h2 id="handshake-pairing" tabindex="-1"><a class="header-anchor" href="#handshake-pairing">#</a> Handshake + pairing</h2><ol><li>Client sends <code>hello</code> with node metadata + token (if already paired).</li><li>If not paired, gateway replies <code>error</code> (<code>NOT_PAIRED</code>/<code>UNAUTHORIZED</code>).</li><li>Client sends <code>pair-request</code>.</li><li>Gateway waits for approval, then sends <code>pair-ok</code> and <code>hello-ok</code>.</li></ol><p><code>hello-ok</code> returns <code>serverName</code> and may include <code>canvasHostUrl</code>.</p><h2 id="frames" tabindex="-1"><a class="header-anchor" href="#frames">#</a> Frames</h2><p>Client → Gateway:</p><ul><li><code>req</code> / <code>res</code>: scoped gateway RPC (chat, sessions, config, health, voicewake, skills.bins)</li><li><code>event</code>: node signals (voice transcript, agent request, chat subscribe, exec lifecycle)</li></ul><p>Gateway → Client:</p><ul><li><code>invoke</code> / <code>invoke-res</code>: node commands (<code>canvas.*</code>, <code>camera.*</code>, <code>screen.record</code>, <code>location.get</code>, <code>sms.send</code>)</li><li><code>event</code>: chat updates for subscribed sessions</li><li><code>ping</code> / <code>pong</code>: keepalive</li></ul><p>Legacy allowlist enforcement lived in <code>src/gateway/server-bridge.ts</code> (removed).</p><h2 id="exec-lifecycle-events" tabindex="-1"><a class="header-anchor" href="#exec-lifecycle-events">#</a> Exec lifecycle events</h2><p>Nodes can emit <code>exec.finished</code> or <code>exec.denied</code> events to surface system.run activity. These are mapped to system events in the gateway. (Legacy nodes may still emit <code>exec.started</code>.)</p><p>Payload fields (all optional unless noted):</p><ul><li><code>sessionKey</code> (required): agent session to receive the system event.</li><li><code>runId</code>: unique exec id for grouping.</li><li><code>command</code>: raw or formatted command string.</li><li><code>exitCode</code>, <code>timedOut</code>, <code>success</code>, <code>output</code>: completion details (finished only).</li><li><code>reason</code>: denial reason (denied only).</li></ul><h2 id="tailnet-usage" tabindex="-1"><a class="header-anchor" href="#tailnet-usage">#</a> Tailnet usage</h2><ul><li>Bind the bridge to a tailnet IP: <code>bridge.bind: &quot;tailnet&quot;</code> in <code>~/.opensoul/opensoul.json</code>.</li><li>Clients connect via MagicDNS name or tailnet IP.</li><li>Bonjour does <strong>not</strong> cross networks; use manual host/port or wide-area DNS‑SD when needed.</li></ul><h2 id="versioning" tabindex="-1"><a class="header-anchor" href="#versioning">#</a> Versioning</h2><p>Bridge is currently <strong>implicit v1</strong> (no min/max negotiation). Backward‑compat is expected; add a bridge protocol version field before any breaking changes.</p>',26)])])}const u=o(t,[["render",n]]);export{h as __pageData,u as default};
